/* TM_CL22001_Dao_retrieveRecExcclcSnpwList */ SELECT rec_delng_year, rec_eqp_cd_nm, ( SELECT cmmn_cd_dc FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2003' AND cmmn_cd = rec_eqp_cd_nm ) AS elcpwstn_nm, mon01_sbmt_qy, mon01_tm1s_amt, mon01_tm2s_amt, mon01_tm3s_amt, mon01_tm4s_amt, mon01_accnut_snrn, mon02_sbmt_qy, mon02_tm1s_amt, mon02_tm2s_amt, mon02_tm3s_amt, mon02_tm4s_amt, mon02_accnut_snrn, mon03_sbmt_qy, mon03_tm1s_amt, mon03_tm2s_amt, mon03_tm3s_amt, mon03_tm4s_amt, mon03_accnut_snrn, mon04_sbmt_qy, mon04_tm1s_amt, mon04_tm2s_amt, mon04_tm3s_amt, mon04_tm4s_amt, mon04_accnut_snrn, mon05_sbmt_qy, mon05_tm1s_amt, mon05_tm2s_amt, mon05_tm3s_amt, mon05_tm4s_amt, mon05_accnut_snrn, mon06_sbmt_qy, mon06_tm1s_amt, mon06_tm2s_amt, mon06_tm3s_amt, mon06_tm4s_amt, mon06_accnut_snrn, mon07_sbmt_qy, mon07_tm1s_amt, mon07_tm2s_amt, mon07_tm3s_amt, mon07_tm4s_amt, mon07_accnut_snrn, mon08_sbmt_qy, mon08_tm1s_amt, mon08_tm2s_amt, mon08_tm3s_amt, mon08_tm4s_amt, mon08_accnut_snrn, mon09_sbmt_qy, mon09_tm1s_amt, mon09_tm2s_amt, mon09_tm3s_amt, mon09_tm4s_amt, mon09_accnut_snrn, mon10_sbmt_qy, mon10_tm1s_amt, mon10_tm2s_amt, mon10_tm3s_amt, mon10_tm4s_amt, mon10_accnut_snrn, mon11_sbmt_qy, mon11_tm1s_amt, mon11_tm2s_amt, mon11_tm3s_amt, mon11_tm4s_amt, mon11_accnut_snrn, mon12_sbmt_qy, mon12_tm1s_amt, mon12_tm2s_amt, mon12_tm3s_amt, mon12_tm4s_amt, mon12_accnut_snrn, ROUND(( NVL(mon01_sbmt_qy, 0) + NVL(mon02_sbmt_qy, 0) + NVL(mon03_sbmt_qy, 0) + NVL(mon04_sbmt_qy, 0) + NVL(mon05_sbmt_qy, 0) + NVL(mon06_sbmt_qy, 0) + NVL(mon07_sbmt_qy, 0) + NVL(mon08_sbmt_qy, 0) + NVL(mon09_sbmt_qy, 0) + NVL(mon10_sbmt_qy, 0) + NVL(mon11_sbmt_qy, 0) + NVL(mon12_sbmt_qy, 0) ), 0) AS totqy, ROUND(( NVL(mon01_accnut_snrn, 0) + NVL(mon02_accnut_snrn, 0) + NVL(mon03_accnut_snrn, 0) + NVL(mon04_accnut_snrn, 0) + NVL(mon05_accnut_snrn, 0) + NVL(mon06_accnut_snrn, 0) + NVL(mon07_accnut_snrn, 0) + NVL(mon08_accnut_snrn, 0) + NVL(mon09_accnut_snrn, 0) + NVL(mon10_accnut_snrn, 0) + NVL(mon11_accnut_snrn, 0) + NVL(mon12_accnut_snrn, 0) ), 0) AS tamt FROM ( SELECT rec_delng_year, LPAD(rec_delng_mt, 2, '0') AS rec_delng_mt, rec_eqp_cd_nm, rec_excclc_sbmt_qy, rec_excclc_tm1s_amt, rec_excclc_tm2s_amt, rec_excclc_tm3s_amt, rec_excclc_tm4s_amt, rec_accnut_snrn FROM tm_cl22001 WHERE rec_delng_year = SUBSTR(#{strtDt}, 0, 4) AND rec_eqp_cd_nm IN ( SELECT cmmn_cd FROM (
) )
AND rec_eqp_cd_nm = #{ecsElcpwstnDivCd}
) PIVOT ( MAX(rec_excclc_sbmt_qy) AS sbmt_qy, MAX(rec_excclc_tm1s_amt) AS tm1s_amt, MAX(rec_excclc_tm2s_amt) AS tm2s_amt, MAX(rec_excclc_tm3s_amt) AS tm3s_amt, MAX(rec_excclc_tm4s_amt) AS tm4s_amt, MAX(rec_accnut_snrn) AS accnut_snrn FOR rec_delng_mt IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12 ) ) ORDER BY rec_delng_year, rec_eqp_cd_nm

mapper.delete:
/* TM_CL22001_Dao_deleteRecExcclcSnpwList */
DELETE FROM
	tm_cl22001
WHERE
	rec_delng_year = #{recDelngYear}
	AND rec_delng_mt = #{recDelngMt}
	AND rec_eqp_cd_nm = #{recEqpCdNm}
